from collections import deque

class Solution:
    def maxDepth(self, nodes):
        # 空树或根节点为空，深度为 0
        if not nodes or nodes[0] == "#":
            return 0

        # 队列中存储当前存在节点的深度
        queue = deque([1])
        index = 1
        ans = 1

        # 按层序数组模拟 BFS
        while queue:
            depth = queue.popleft()

            # 处理左子节点
            if index < len(nodes):
                if nodes[index] != "#":
                    queue.append(depth + 1)
                    ans = max(ans, depth + 1)
                index += 1

            # 处理右子节点
            if index < len(nodes):
                if nodes[index] != "#":
                    queue.append(depth + 1)
                    ans = max(ans, depth + 1)
                index += 1

        return ans
```

```java
import java.util.*;

class Solution {
    public int maxDepth(String[] nodes) {
        // 如果没有节点，或者根节点为空，深度为 0
        if (nodes == null || nodes.length == 0 || nodes[0].equals("#")) {
            return 0;
        }

        // 队列中存储每个存在节点对应的深度
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(1);

        int index = 1;
        int ans = 1;

        // 按层序顺序处理每个存在的节点
        while (!queue.isEmpty()) {
            int depth = queue.poll();

            // 处理左子节点
            if (index < nodes.length) {
                if (!nodes[index].equals("#")) {
                    queue.offer(depth + 1);
                    ans = Math.max(ans, depth + 1);
                }
                index++;
            }

            // 处理右子节点
            if (index < nodes.length) {
                if (!nodes[index].equals("#")) {
                    queue.offer(depth + 1);
                    ans = Math.max(ans, depth + 1);
                }
                index++;
            }
        }

        return ans;
    }
}
